// Copyright (c) HashiCorp, Inc.// SPDX-License-Identifier: MPL-2.0package tf5serverimport (	"context"	"errors"	"net/rpc"	"github.com/hashicorp/go-plugin"	"github.com/hashicorp/terraform-plugin-go/tfprotov5"	"github.com/hashicorp/terraform-plugin-go/tfprotov5/internal/tfplugin5"	"google.golang.org/grpc")// GRPCProviderPlugin is an implementation of the// github.com/hashicorp/go-plugin#Plugin and// github.com/hashicorp/go-plugin#GRPCPlugin interfaces, indicating how to// serve tfprotov5.ProviderServers as gRPC plugins for go-plugin.type GRPCProviderPlugin struct {	GRPCProvider fprotov5.ProviderServer	Opts[]ServeOpt	Namestring}// Server always returns an error; we're only implementing the GRPCPlugin// interface, not the Plugin interface.*GRPCProviderPlugin) Server(*plugin.MuxBroker) (interface{}, error) {	return nil, errors.New("terraform-plugin-go only implements gRPC servers")}// Client always returns an error; we're only implementing the GRPCPlugin// interface, not the Plugin interface.*GRPCProviderPlugin) Client(*plugin.MuxBroker, *rpc.Client) (interface{}, error) {	return nil, errors.New("terraform-plugin-go only implements gRPC servers")}// GRPCClient always returns an error; we're only implementing the server half// of the interface.*GRPCProviderPlugin) GRPCClient(context.Context, *plugin.GRPCBroker, *grpc.ClientConn) (interface{}, error) {	return nil, errors.New("terraform-plugin-go only implements gRPC servers")}// GRPCServer registers the gRPC provider server with the gRPC server that// go-plugin is standing up.*GRPCProviderPlugin) GRPCServer(broker *plugin.GRPCBroker, s *grpc.Server) error {	tfplugin5.RegisterProviderServer(s, New(p.Name, p.GRPCProvider(), p.Opts...))	return nil}